// srad.cu : CUDA implementation of SRAD

#define OPEN
#define ITERATION
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include "srad.h"

void random_matrix(float *I, int rows, int cols);

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <no. of threads><lamda> <no. of iter>\n", argv[0]);
    fprintf(stderr, "\t<rows>   - number of rows\n");
    fprintf(stderr, "\t<cols>    - number of cols\n");
    fprintf(stderr, "\t<y1>      - y1 value of the speckle\n");
    fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
    fprintf(stderr, "\t<x1>      - x1 value of the speckle\n");
    fprintf(stderr, "\t<x2>      - x2 value of the speckle\n");
    fprintf(stderr, "\t<no. of threads>  - no. of threads\n");
    fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
    fprintf(stderr, "\t<no. of iter>   - number of iterations\n");
    exit(1);
}

// Kernel declarations (defined in srad_kernel.cu)
void srad_cuda_1(
    float *d_J,
    float *d_C,
    float *d_dN,
    float *d_dS,
    float *d_dW,
    float *d_dE,
    int *d_iN,
    int *d_iS,
    int *d_jW,
    int *d_jE,
    float q0sqr,
    int rows,
    int cols
);

void srad_cuda_2(
    float *d_J,
    float *d_C,
    float *d_dN,
    float *d_dS,
    float *d_dW,
    float *d_dE,
    int *d_iS,
    int *d_jE,
    float lambda,
    int rows,
    int cols
);

int main(int argc, char* argv[])
{
    int rows, cols, size_I, size_R, niter = 10, iter;
    float *I, *J, q0sqr, sum, sum2, tmp, meanROI, varROI;
    int *iN, *iS, *jE, *jW;
    float *dN, *dS, *dW, *dE;
    int r1, r2, c1, c2;
    float *c;
    float lambda;
    int i, j;
    int nthreads;

    if (argc == 10)
    {
        rows = atoi(argv[1]);
        cols = atoi(argv[2]);
        if ((rows % 16 != 0) || (cols % 16 != 0)) {
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1 = atoi(argv[3]);
        r2 = atoi(argv[4]);
        c1 = atoi(argv[5]);
        c2 = atoi(argv[6]);
        nthreads = atoi(argv[7]);
        lambda = atof(argv[8]);
        niter = atoi(argv[9]);
    }
    else {
        usage(argc, argv);
    }

    size_I = cols * rows;
    size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

    I = (float *)malloc(size_I * sizeof(float));
    J = (float *)malloc(size_I * sizeof(float));
    c = (float *)malloc(sizeof(float) * size_I);

    iN = (int *)malloc(sizeof(int) * rows);
    iS = (int *)malloc(sizeof(int) * rows);
    jW = (int *)malloc(sizeof(int) * cols);
    jE = (int *)malloc(sizeof(int) * cols);

    dN = (float *)malloc(sizeof(float) * size_I);
    dS = (float *)malloc(sizeof(float) * size_I);
    dW = (float *)malloc(sizeof(float) * size_I);
    dE = (float *)malloc(sizeof(float) * size_I);

    for (i = 0; i < rows; i++) {
        iN[i] = i - 1;
        iS[i] = i + 1;
    }
    for (j = 0; j < cols; j++) {
        jW[j] = j - 1;
        jE[j] = j + 1;
    }
    iN[0] = 0;
    iS[rows - 1] = rows - 1;
    jW[0] = 0;
    jE[cols - 1] = cols - 1;

    printf("Randomizing the input matrix\n");

    random_matrix(I, rows, cols);

    for (int k = 0; k < size_I; k++) {
        J[k] = (float)exp(I[k]);
    }

    printf("Start the SRAD main loop\n");

    // Allocate device memory
    float *d_J, *d_C, *d_dN, *d_dS, *d_dW, *d_dE;
    int *d_iN, *d_iS, *d_jW, *d_jE;

    cudaMalloc((void **)&d_J, sizeof(float) * size_I);
    cudaMalloc((void **)&d_C, sizeof(float) * size_I);
    cudaMalloc((void **)&d_dN, sizeof(float) * size_I);
    cudaMalloc((void **)&d_dS, sizeof(float) * size_I);
    cudaMalloc((void **)&d_dW, sizeof(float) * size_I);
    cudaMalloc((void **)&d_dE, sizeof(float) * size_I);
    cudaMalloc((void **)&d_iN, sizeof(int) * rows);
    cudaMalloc((void **)&d_iS, sizeof(int) * rows);
    cudaMalloc((void **)&d_jW, sizeof(int) * cols);
    cudaMalloc((void **)&d_jE, sizeof(int) * cols);

    // Copy data to device
    cudaMemcpy(d_J, J, sizeof(float) * size_I, cudaMemcpyHostToDevice);
    cudaMemcpy(d_iN, iN, sizeof(int) * rows, cudaMemcpyHostToDevice);
    cudaMemcpy(d_iS, iS, sizeof(int) * rows, cudaMemcpyHostToDevice);
    cudaMemcpy(d_jW, jW, sizeof(int) * cols, cudaMemcpyHostToDevice);
    cudaMemcpy(d_jE, jE, sizeof(int) * cols, cudaMemcpyHostToDevice);

#ifdef ITERATION
    for (iter = 0; iter < niter; iter++) {
#endif
        sum = 0; sum2 = 0;

        // Copy J back to host for ROI computation
        cudaMemcpy(J, d_J, sizeof(float) * size_I, cudaMemcpyDeviceToHost);

        for (i = r1; i <= r2; i++) {
            for (j = c1; j <= c2; j++) {
                tmp = J[i * cols + j];
                sum += tmp;
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI = (sum2 / size_R) - meanROI * meanROI;
        q0sqr = varROI / (meanROI * meanROI);

        // Launch kernel 1
        srad_cuda_1(d_J, d_C, d_dN, d_dS, d_dW, d_dE,
                    d_iN, d_iS, d_jW, d_jE,
                    q0sqr, rows, cols);

        // Launch kernel 2
        srad_cuda_2(d_J, d_C, d_dN, d_dS, d_dW, d_dE,
                    d_iS, d_jE,
                    lambda, rows, cols);

#ifdef ITERATION
    }
#endif

    // Copy result back to host
    cudaMemcpy(J, d_J, sizeof(float) * size_I, cudaMemcpyDeviceToHost);

#ifdef OUTPUT
    for (i = 0; i < rows; i++) {
        for (j = 0; j < cols; j++) {
            printf("%.5f ", J[i * cols + j]);
        }
        printf("\n");
    }
#endif

    printf("Computation Done\n");

    // Free device memory
    cudaFree(d_J);
    cudaFree(d_C);
    cudaFree(d_dN);
    cudaFree(d_dS);
    cudaFree(d_dW);
    cudaFree(d_dE);
    cudaFree(d_iN);
    cudaFree(d_iS);
    cudaFree(d_jW);
    cudaFree(d_jE);

    // Free host memory
    free(I);
    free(J);
    free(iN); free(iS); free(jW); free(jE);
    free(dN); free(dS); free(dW); free(dE);
    free(c);

    return 0;
}

void random_matrix(float *I, int rows, int cols)
{
    srand(7);
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            I[i * cols + j] = rand() / (float)RAND_MAX;
#ifdef OUTPUT
            //printf("%g ", I[i * cols + j]);
#endif
        }
#ifdef OUTPUT
        //printf("\n");
#endif
    }
}

